/**
 * event
 * @name f_OpenCommonPopUp
 * @description 공통팝업 열기
 */
scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (gubun1) {
        case "Vessel":
            udc_hhvslcd.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_hhvslcd, ed_cnd_hhvsl)
                , ed_cnd_hhvslcd.getValue().trim()
                , ed_cnd_hhvsl.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Vessel,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Loading":
            udc_hhlodcd.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_hhlodcd, ed_cnd_hhlodnm)
                , ed_cnd_hhlodcd.getValue().trim()
                , ed_cnd_hhlodnm.getValue()
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Loading,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Discharge":
            udc_hhdisccd.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_hhdisccd, ed_cnd_hhdiscnm)
                , ed_cnd_hhdisccd.getValue().trim()
                , ed_cnd_hhdiscnm.getValue()
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Discharge,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "DEPT":
            udc_deptCd.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_deptCd, ed_cnd_deptNm)
                , ed_cnd_deptCd.getValue().trim()
                , ed_cnd_deptNm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "DEPT,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Salesman":
            udc_salesman.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_salesman, ed_cnd_salesmanNm)
                , ed_cnd_salesman.getValue().trim()
                , ed_cnd_salesmanNm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Salesman,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "B/L PIC":
            udc_pic.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_pic, ed_cnd_picNm)
                , ed_cnd_pic.getValue().trim()
                , ed_cnd_picNm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "B/L PIC,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Country":
            udc_cntyCd.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_cnd_cntyCd, ed_cnd_cntyNm)
                , ed_cnd_cntyCd.getValue().trim()
