                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Country,Code,Name"
                , pNoDataCloseTF
            );
            break;
    }
};

/**
 * event
 * @name f_downExcelSheet
 * @description 엑셀다운로드
 */
scwin.f_downExcelSheet = async function () {
    if (ds_houseblList.getRowCount()) {
        let cfrm = await $c.win.confirm("House B/L List를 EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            let sheetTitle = "House BL List";  // '/'있으면 저장안됨.
            // $c.gus.cfGridToExcel(gr_houseblList, sheetTitle, sheetTitle, 1 + 2 + 4 + 8 + 16);
            const options = {
                "fileName": sheetTitle + ".xlsx",
                "sheetName": sheetTitle,
                "hiddenVisible": "true",
                "removeColumns": "0,1,2",
                "colMerge": "true",
                "colMergeTextAlign": "top",
            };
            $c.data.downloadGridViewExcel(gr_houseblList, options);
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
    }
};

/**
 * event
 * @name f_dateLoading
 * @description hhio에따른 date default
 */
scwin.f_dateLoading = function () {
    if (rd_cnd_hhio.getValue() == "O") {
        ica_cnd_hhetdFrom.setValue(scwin.strPreDate);
        ica_cnd_hhetdTo.setValue(scwin.strCurDate);
        ica_cnd_hhetaFrom.setValue("");
        ica_cnd_hhetaTo.setValue("");
    } else {
        ica_cnd_hhetdFrom.setValue("");
        ica_cnd_hhetdTo.setValue("");
        ica_cnd_hhetaFrom.setValue(scwin.strPreDate);
        ica_cnd_hhetaTo.setValue(scwin.strCurDate);
    }
};

/**
 * event
 * @name udc_hhscd_onblurCodeEvent
 * @description
 */
scwin.udc_hhscd_onblurCodeEvent = function (e) {
    if (!$c.gus.cfCanOpenPopup(ed_cnd_hhscd, ed_cnd_hhs1)) {
        return;
    }

    let strClntNo = ed_cnd_hhscd.getValue().trim();
    if (strClntNo.length > 0) {
        ed_cnd_hhs1.setValue("");
        scwin.f_PopUp('Shipper', 'T');
    } else {
        ed_cnd_hhs1.setValue("");
    }
};

/**
 * event
 * @name udc_hhscd_onclickEvent
 * @description
 */
scwin.udc_hhscd_onclickEvent = function (e) {
    scwin.f_PopUp('Shipper', 'F');
};

