/**
 * event
 * @name gr_houseblList_oncelldblclick
 * @description
 */
scwin.gr_houseblList_oncelldblclick = function (row, col, colid) {
    let rowObj = ds_houseblList.getRowJSON(row);
    if (colid == "trYn") {
        //개발대상에서 제외된 화면이라 막음
        return;
        let param = {
            hblNo: rowObj.hhblno,
        }
        //프로그램 목록에 없음
        $c.win.openMenu("컨테이너 경로 관리", "/ui/il/custsv/tr/cs_108_01_02b.xml", "cs_108_01_02b", param, { openAction: "exist" });
    } else {
        if (rowObj.hhio == "O") {  // OUTBOUND
            if (rowObj.autono == "DIRECT" && rowObj.hhbltype != "B") {  //Direct
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    blno: rowObj.hhblno,
                    mhno: rowObj.mhno,
                    linkcheck: "2",
                }
                //$c.win.openMenu("Direct B/L", "/ui/il/seaout/sobl/se_107_01_01b.xml", "se_107_01_01b", param, { openAction: "exist" });

                // 기능개선 추가 (O-0074)
                 $c.win.openMenu("Export House B/L (New)", "/ui/il/seaout/sobl/se_105_01_05b.xml", "se_105_01_05b", param, { openAction: "exist" });
            } else if (rowObj.autono == "DIRECT" && rowObj.hhbltype == "B") {  // bulk
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    mhno: rowObj.mhno,
                    linkcheck: "2",
                }
                $c.win.openMenu("Export Bulk B/L", "/ui/il/seaout/sobl/se_108_01_01b.xml", "se_108_01_01b", param, { openAction: "exist" });
            } else {  //  house
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    blno: rowObj.hhblno,
                    mhno: rowObj.mhno,
                    linkcheck: "2",
                }
                $c.win.openMenu("Export House B/L (New)", "/ui/il/seaout/sobl/se_105_01_05b.xml", "se_105_01_05b", param, { openAction: "exist" });
            }
        } else {  // INBOUND ,우선 bulk ,house
            if (rowObj.autono == "DIRECT" && rowObj.hhbltype == "B") {  //Bulk
                //개발대상에서 제외된 화면이라 막음
                return;
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    mhno: rowObj.mhno,
                    linkcheck: "2",
                }
                //프로그램 목록에 없음
                $c.win.openMenu("Import Bulk B/L", "/ui/il/seainb/sibl/se_203_01_01b.xml", "se_203_01_01b", param, { openAction: "exist" });
            } else {  //HOuse
                let param = {
                    kcomcd: scwin.hd_kcomcd,
                    blno: rowObj.hhblno,
                    mhno: rowObj.mhno,
                    linkcheck: "2",
                }
                $c.win.openMenu("Import House B/L (New)", "/ui/il/seainb/sibl/se_201_01_03b.xml", "se_201_01_03b", param, { openAction: "exist" });
            }
        }
    }
};

/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
    if (ds_houseblList.getRowCount()) {
        // gr_houseblList.setColumnColor("trYn", "#007FFF");
        let cnt = 0;
        let documentNo = "";
        //expression 사용하니 정렬 안되서 값 직접 변경하는것으로 변경
        let cols = [
            "hhmblno",
            "srno",
            "hhactcust",
            "hhactcustnm",
            "hhs1",
            "hhc1",
            "hhn1",
            "hhvsl",
            "hhvyg",
            "hhlodcd",
            "hhdisccd",
            "hhagentnm",
            "hhlinernm",
            "hhetd",
            "hheta",
            "pic",
            "hhio",
            "autono",
            "hhbltype",
            "trYn",
            "hhmitem2",
            "hhpkg",
            "hhunit",
            "hhgwgt",
            "hhnwgt",
            "hhmsr",
            "hhcnt1type",
            "hhcnt1",
            "hhcnt2type",
            "hhcnt2",
            "hhcnt3type",
            "hhcnt3",
            "hhcnt4type",
            "hhcnt4",
            "mccntno",
            "hhliner",
        ];
        for (let i = 0; i < ds_houseblList.getRowCount(); i++) {
            if (documentNo != ds_houseblList.getCellData(i, "hhblno")) {
                cnt++;
            }
            documentNo = ds_houseblList.getCellData(i, "hhblno");
            for (let colid of cols) {
                if (ds_houseblList.getCellData(i, colid) == "") {
                    ds_houseblList.setCellData(i, colid, "-");
                }
            }
        }

        totalRows_item.setValue(ds_houseblList.getRowCount()); // 조회된 건수를 매출입항목Grid 하단에 표시한다.
        totalRows_item2.setValue("총 " + cnt + "건"); // 조회된 건수를 매출입항목Grid 하단에 표시한다.

        scwin.f_set("RETRIEVE");
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
    }
};

